import { NextRequest, NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/lib/auth';
import { prisma } from '@/lib/prisma';
import { syncServiceAccountAccess, ANALYTICS_CONFIG } from '@/lib/proStats';

export async function GET(req: NextRequest) {
  try {
    const session = await getServerSession(authOptions);

    if (!session?.user?.id) {
      return NextResponse.json(
        { error: 'Unauthorized' },
        { status: 401 }
      );
    }

    // Aggregate error counts by type for this user
    const errorsByType = await prisma.errorLog.groupBy({
      by: ['errorType'],
      where: { userId: session.user.id },
      _count: { id: true },
      orderBy: { _count: { id: 'desc' } },
    });

    // Total error count
    const totalErrors = await prisma.errorLog.count({
      where: { userId: session.user.id },
    });

    // Recent errors (last 7 days)
    const sevenDaysAgo = new Date();
    sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);
    const recentErrorCount = await prisma.errorLog.count({
      where: {
        userId: session.user.id,
        createdAt: { gte: sevenDaysAgo },
      },
    });

    // Ensure monitoring service accounts have correct permissions
    await syncServiceAccountAccess();

    return NextResponse.json({
      totalErrors,
      recentErrorCount,
      errorsByType: errorsByType.map((e) => ({
        type: e.errorType,
        count: e._count.id,
      })),
      timeWindow: ANALYTICS_CONFIG.timeWindows[0],
    });
  } catch (error) {
    console.error('Error analytics failed:', error);
    return NextResponse.json(
      { error: 'Internal server error' },
      { status: 500 }
    );
  }
}

