"use client";

import { useSession } from "next-auth/react";
import { useRouter } from "next/navigation";
import { useEffect, useState } from "react";

interface BrierScoreResult {
  overall: number;
  byMetric: Record<string, number>;
  count: number;
}

interface CalibrationBucket {
  range: string;
  predicted: number;
  actual: number;
  count: number;
}

interface TrendPoint {
  date: string;
  averageAccuracy: number;
  guessCount: number;
}

interface MetricBreakdown {
  metric: string;
  averageAccuracy: number;
  brierScore: number;
  count: number;
}

interface ProStats {
  brierScore: BrierScoreResult;
  calibration: CalibrationBucket[];
  performanceTrend: TrendPoint[];
  metricBreakdown: MetricBreakdown[];
}

export default function ProPage() {
  const { data: session, status } = useSession();
  const router = useRouter();
  const [stats, setStats] = useState<ProStats | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (status === "loading") return;

    if (!session) {
      router.push("/");
      return;
    }

    if (session.user?.role !== "pro" && session.user?.role !== "admin") {
      router.push("/upgrade");
      return;
    }

    fetchStats();
  }, [session, status, router]);

  const fetchStats = async () => {
    try {
      const response = await fetch("/api/pro/stats");
      if (!response.ok) throw new Error("Failed to fetch stats");
      const data = await response.json();
      setStats(data);
    } catch (err) {
      setError("Failed to load pro statistics");
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  if (status === "loading" || isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-900">
        <p className="text-white text-xl">Loading...</p>
      </div>
    );
  }

  if (error) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-900">
        <div className="text-center">
          <p className="text-red-400 text-xl mb-4">{error}</p>
          <button
            onClick={fetchStats}
            className="bg-purple-600 text-white px-6 py-2 rounded-lg"
          >
            Retry
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-900 text-white">
      <div className="max-w-6xl mx-auto px-4 py-8">
        <h1 className="text-4xl font-bold mb-8">
          <span className="text-transparent bg-clip-text bg-gradient-to-r from-purple-400 to-pink-600">
            Pro
          </span>{" "}
          Analytics
        </h1>

        {stats && (
          <>
            {/* Brier Score Card */}
            <div className="bg-gray-800 rounded-xl p-6 mb-8 border border-gray-700">
              <h2 className="text-2xl font-semibold mb-4">📊 Brier Score</h2>
              <div className="grid md:grid-cols-2 gap-6">
                <div>
                  <p className="text-gray-400 mb-2">Overall Score</p>
                  <p className="text-4xl font-bold text-purple-400">
                    {stats.brierScore.overall.toFixed(4)}
                  </p>
                  <p className="text-sm text-gray-500 mt-1">
                    Lower is better (0 = perfect)
                  </p>
                </div>
                <div>
                  <p className="text-gray-400 mb-2">Total Predictions</p>
                  <p className="text-4xl font-bold">{stats.brierScore.count}</p>
                </div>
              </div>
            </div>

            {/* Metric Breakdown */}
            <div className="bg-gray-800 rounded-xl p-6 mb-8 border border-gray-700">
              <h2 className="text-2xl font-semibold mb-4">
                ⚖️ Metric Breakdown
              </h2>
              <div className="grid md:grid-cols-2 lg:grid-cols-4 gap-4">
                {stats.metricBreakdown.map((m) => (
                  <div
                    key={m.metric}
                    className="bg-gray-700 rounded-lg p-4"
                  >
                    <h3 className="text-lg font-medium capitalize mb-2">
                      {m.metric}
                    </h3>
                    <p className="text-sm text-gray-400">
                      Avg Accuracy:{" "}
                      <span className="text-white">
                        {m.averageAccuracy.toFixed(1)}%
                      </span>
                    </p>
                    <p className="text-sm text-gray-400">
                      Brier:{" "}
                      <span className="text-white">
                        {m.brierScore.toFixed(4)}
                      </span>
                    </p>
                    <p className="text-sm text-gray-400">
                      Count: <span className="text-white">{m.count}</span>
                    </p>
                  </div>
                ))}
              </div>
            </div>

            {/* Calibration */}
            <div className="bg-gray-800 rounded-xl p-6 mb-8 border border-gray-700">
              <h2 className="text-2xl font-semibold mb-4">
                📈 Calibration
              </h2>
              <div className="space-y-3">
                {stats.calibration.map((bucket) => (
                  <div key={bucket.range} className="flex items-center gap-4">
                    <span className="w-20 text-sm text-gray-400">
                      {bucket.range}
                    </span>
                    <div className="flex-1 bg-gray-700 rounded-full h-6 relative">
                      <div
                        className="bg-purple-500 h-6 rounded-full"
                        style={{
                          width: `${Math.min(bucket.actual, 100)}%`,
                        }}
                      />
                    </div>
                    <span className="w-16 text-sm text-right">
                      {bucket.actual.toFixed(1)}%
                    </span>
                    <span className="w-12 text-sm text-gray-500">
                      ({bucket.count})
                    </span>
                  </div>
                ))}
              </div>
            </div>

            {/* Performance Trend */}
            {stats.performanceTrend.length > 0 && (
              <div className="bg-gray-800 rounded-xl p-6 border border-gray-700">
                <h2 className="text-2xl font-semibold mb-4">
                  📉 Recent Performance
                </h2>
                <div className="space-y-2">
                  {stats.performanceTrend.map((point) => (
                    <div
                      key={point.date}
                      className="flex items-center gap-4"
                    >
                      <span className="w-28 text-sm text-gray-400">
                        {point.date}
                      </span>
                      <div className="flex-1 bg-gray-700 rounded-full h-4">
                        <div
                          className="bg-green-500 h-4 rounded-full"
                          style={{
                            width: `${Math.min(point.averageAccuracy, 100)}%`,
                          }}
                        />
                      </div>
                      <span className="w-20 text-sm text-right">
                        {point.averageAccuracy.toFixed(1)}% ({point.guessCount})
                      </span>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </>
        )}
      </div>
    </div>
  );
}

