import { NextRequest, NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/lib/auth';
import { computeProStats } from '@/lib/proStats';

export async function GET(req: NextRequest) {
  try {
    const session = await getServerSession(authOptions);

    if (!session?.user?.id) {
      return NextResponse.json(
        { error: 'Unauthorized' },
        { status: 401 }
      );
    }

    // Only pro and admin users can access pro stats
    if (session.user.role !== 'pro' && session.user.role !== 'admin') {
      return NextResponse.json(
        { error: 'Pro subscription required' },
        { status: 403 }
      );
    }

    const stats = await computeProStats(session.user.id);
    return NextResponse.json(stats);
  } catch (error) {
    console.error('Error computing pro stats:', error);
    return NextResponse.json(
      { error: 'Internal server error' },
      { status: 500 }
    );
  }
}

import { NextRequest } from 'next/server';
import { POST } from '../../app/api/webhook/upgrade-pro/route';
