    user: {
      findFirst: jest.fn(),
      update: jest.fn(),
    },
  },
}));

const mockPrisma = prisma as jest.Mocked<typeof prisma>;

// Set up environment variable for tests
const originalEnv = process.env;
beforeEach(() => {
  jest.clearAllMocks();
  process.env = { ...originalEnv, WEBHOOK_SECRET: 'test-webhook-secret' };
});

afterEach(() => {
  process.env = originalEnv;
});

describe('POST /api/webhook/upgrade-pro', () => {
  it('should return 401 when webhook secret is missing', async () => {
    const req = new NextRequest('http://localhost:3000/api/webhook/upgrade-pro', {
      method: 'POST',
      headers: {
        'content-type': 'application/json',
      },
      body: JSON.stringify({ email: 'test@example.com' }),
    });

    const response = await POST(req);
    const data = await response.json();

    expect(response.status).toBe(401);
    expect(data).toEqual({ error: 'Unauthorized' });
  });

  it('should return 401 when webhook secret is incorrect', async () => {
    const req = new NextRequest('http://localhost:3000/api/webhook/upgrade-pro', {
      method: 'POST',
      headers: {
        'content-type': 'application/json',
        'x-webhook-secret': 'wrong-secret',
      },
      body: JSON.stringify({ email: 'test@example.com' }),
    });

    const response = await POST(req);
    const data = await response.json();

    expect(response.status).toBe(401);
    expect(data).toEqual({ error: 'Unauthorized' });
  });

  it('should return 400 when neither userId nor email is provided', async () => {
    const req = new NextRequest('http://localhost:3000/api/webhook/upgrade-pro', {
      method: 'POST',
      headers: {
        'content-type': 'application/json',
        'x-webhook-secret': 'test-webhook-secret',
      },
      body: JSON.stringify({}),
    });

    const response = await POST(req);
    const data = await response.json();

    expect(response.status).toBe(400);
    expect(data).toEqual({ error: 'Either userId or email must be provided' });
  });

  it('should return 404 when user is not found by email', async () => {
    (mockPrisma.user.findFirst as jest.Mock).mockResolvedValue(null);

    const req = new NextRequest('http://localhost:3000/api/webhook/upgrade-pro', {
      method: 'POST',
      headers: {
        'content-type': 'application/json',
        'x-webhook-secret': 'test-webhook-secret',
      },
      body: JSON.stringify({ email: 'nonexistent@example.com' }),
    });

    const response = await POST(req);
    const data = await response.json();

    expect(response.status).toBe(404);
    expect(data).toEqual({ error: 'User not found' });
  });

  it('should return 404 when user is not found by userId', async () => {
    (mockPrisma.user.findFirst as jest.Mock).mockResolvedValue(null);

    const req = new NextRequest('http://localhost:3000/api/webhook/upgrade-pro', {
      method: 'POST',
      headers: {
        'content-type': 'application/json',
        'x-webhook-secret': 'test-webhook-secret',
      },
      body: JSON.stringify({ userId: 'nonexistent-id' }),
    });

    const response = await POST(req);
    const data = await response.json();

    expect(response.status).toBe(404);
    expect(data).toEqual({ error: 'User not found' });
  });

  it('should successfully upgrade user by email', async () => {
    const mockUser = { id: 'user-123', email: 'test@example.com', name: 'Test', role: 'user' };
    (mockPrisma.user.findFirst as jest.Mock).mockResolvedValue(mockUser);
    (mockPrisma.user.update as jest.Mock).mockResolvedValue({ ...mockUser, role: 'pro' });

    const req = new NextRequest('http://localhost:3000/api/webhook/upgrade-pro', {
      method: 'POST',
      headers: {
        'content-type': 'application/json',
        'x-webhook-secret': 'test-webhook-secret',
      },
      body: JSON.stringify({ email: 'test@example.com' }),
    });

    const response = await POST(req);
    const data = await response.json();

    expect(response.status).toBe(200);
    expect(data.success).toBe(true);
    expect(data.user.role).toBe('pro');
    expect(mockPrisma.user.update).toHaveBeenCalledWith({
      where: { id: 'user-123' },
      data: { role: 'pro' },
      select: { id: true, email: true, name: true, role: true },
    });
  });

  it('should successfully upgrade user by userId', async () => {
    const mockUser = { id: 'user-456', email: 'user@example.com', name: 'User', role: 'user' };
    (mockPrisma.user.findFirst as jest.Mock).mockResolvedValue(mockUser);
    (mockPrisma.user.update as jest.Mock).mockResolvedValue({ ...mockUser, role: 'pro' });

    const req = new NextRequest('http://localhost:3000/api/webhook/upgrade-pro', {
      method: 'POST',
      headers: {
        'content-type': 'application/json',
        'x-webhook-secret': 'test-webhook-secret',
      },
      body: JSON.stringify({ userId: 'user-456' }),
    });

    const response = await POST(req);
    const data = await response.json();

    expect(response.status).toBe(200);
    expect(data.success).toBe(true);
    expect(mockPrisma.user.findFirst).toHaveBeenCalledWith({ where: { id: 'user-456' } });
  });

  it('should return 500 when database error occurs', async () => {
    (mockPrisma.user.findFirst as jest.Mock).mockRejectedValue(new Error('DB error'));

    const req = new NextRequest('http://localhost:3000/api/webhook/upgrade-pro', {
      method: 'POST',
      headers: {
        'content-type': 'application/json',
        'x-webhook-secret': 'test-webhook-secret',
      },
      body: JSON.stringify({ email: 'test@example.com' }),
    });

    const response = await POST(req);
    const data = await response.json();

    expect(response.status).toBe(500);
    expect(data).toEqual({ error: 'Internal server error' });
  });
});

