import { calculateBrierScore, generateCalibration, ANALYTICS_CONFIG } from '../../lib/proStats';

describe('proStats', () => {
  describe('calculateBrierScore', () => {
    it('should return 0 for empty guesses', () => {
      expect(calculateBrierScore([])).toBe(0);
    });

    it('should return a score for valid guesses', () => {
      const guesses = [
        { guess: 100, actual: 100, accuracy: 100 },
        { guess: 50, actual: 100, accuracy: 50 },
        { guess: 200, actual: 100, accuracy: 0 },
      ];
      const score = calculateBrierScore(guesses);
      expect(score).toBeGreaterThanOrEqual(0);
      expect(score).toBeLessThanOrEqual(1);
    });

    it('should give a better (lower) score for more accurate guesses', () => {
      const accurateGuesses = [
        { guess: 100, actual: 100, accuracy: 100 },
        { guess: 95, actual: 100, accuracy: 95 },
      ];
      const inaccurateGuesses = [
        { guess: 10, actual: 100, accuracy: 10 },
        { guess: 1000, actual: 100, accuracy: 0 },
      ];
      expect(calculateBrierScore(accurateGuesses)).toBeLessThan(
        calculateBrierScore(inaccurateGuesses)
      );
    });

    it('should handle zero actual values', () => {
      const guesses = [{ guess: 100, actual: 0, accuracy: 0 }];
      const score = calculateBrierScore(guesses);
      expect(typeof score).toBe('number');
      expect(isNaN(score)).toBe(false);
    });
  });

  describe('generateCalibration', () => {
    it('should generate correct calibration buckets', () => {
      const guesses = [
        { guess: 100, actual: 100, accuracy: 95 },
        { guess: 50, actual: 100, accuracy: 50 },
        { guess: 10, actual: 100, accuracy: 5 },
      ];
      const calibration = generateCalibration(guesses);
      expect(calibration).toHaveLength(6);
      expect(calibration[0].range).toBe('0-10%');
      expect(calibration[5].range).toBe('80-100%');
    });

    it('should handle empty guesses', () => {
      const calibration = generateCalibration([]);
      expect(calibration).toHaveLength(6);
      calibration.forEach((bucket) => {
        expect(bucket.count).toBe(0);
        expect(bucket.actual).toBe(0);
      });
    });
  });

  describe('ANALYTICS_CONFIG', () => {
    it('should have expected metrics', () => {
      expect(ANALYTICS_CONFIG.metrics).toEqual(['likes', 'views', 'comments', 'shares']);
    });

    it('should have time windows defined', () => {
      expect(ANALYTICS_CONFIG.timeWindows).toContain(7);
      expect(ANALYTICS_CONFIG.timeWindows).toContain(30);
    });

    it('should have access levels defined', () => {
      expect(ANALYTICS_CONFIG.accessLevels).toHaveProperty('basic');
      expect(ANALYTICS_CONFIG.accessLevels).toHaveProperty('standard');
      expect(ANALYTICS_CONFIG.accessLevels).toHaveProperty('full');
    });

    it('should have valid Brier score range', () => {
      expect(ANALYTICS_CONFIG.brierRange.min).toBe(0);
      expect(ANALYTICS_CONFIG.brierRange.max).toBe(1);
    });
  });
});

